// ============================================================
//  KONFIGURACJA — zmień adresy email
// ============================================================
const TATA_EMAIL = 'burritobukovsky@gmail.com';
const MAMA_EMAIL = 'mama@example.com'; // ← ZMIEŃ NA EMAIL MAMY

// ============================================================
const data = $input.first().json.body || $input.first().json;

const categoryEmoji = {
  'szachy':     '♟️',
  'sprawdzian': '📝',
  'ortodonta':  '🦷',
  'konkurs':    '🏆',
  'inne':       '📌',
  'opieka':     '👨‍👦'
};
const categoryName = {
  'szachy':     'Szachy',
  'sprawdzian': 'Sprawdzian',
  'ortodonta':  'Ortodonta',
  'konkurs':    'Konkurs',
  'inne':       'Inne',
  'opieka':     'Opieka'
};

const emoji   = categoryEmoji[data.category] || '📅';
const catName = categoryName[data.category]  || data.category || 'Wydarzenie';

const dateObj = new Date(data.date + 'T12:00:00');
const days    = ['Niedziela','Poniedziałek','Wtorek','Środa','Czwartek','Piątek','Sobota'];
const months  = ['stycznia','lutego','marca','kwietnia','maja','czerwca',
                 'lipca','sierpnia','września','października','listopada','grudnia'];
const dateStr = `${days[dateObj.getDay()]}, ${dateObj.getDate()} ${months[dateObj.getMonth()]} ${dateObj.getFullYear()}`;
const shortDate = `${dateObj.getDate()} ${months[dateObj.getMonth()]}`;

const timeStr = data.time
  ? (data.timeEnd ? `${data.time} – ${data.timeEnd}` : data.time)
  : 'Cały dzień';

const title = data.title || data.name || '';

const rowStyle = 'display:flex;align-items:flex-start;gap:12px;padding:12px 0;border-bottom:1px solid #eef1f5;';
const labelStyle = 'font-size:11px;color:#8a94a6;font-weight:700;text-transform:uppercase;letter-spacing:.5px;margin-bottom:3px;';
const valueStyle = 'font-size:15px;color:#0f1f3d;font-weight:600;';

let rows = `
  <div style="${rowStyle}">
    <span style="font-size:22px;width:28px;text-align:center;">📅</span>
    <div><div style="${labelStyle}">Data</div><div style="${valueStyle}">${dateStr}</div></div>
  </div>
  <div style="${rowStyle}">
    <span style="font-size:22px;width:28px;text-align:center;">🕐</span>
    <div><div style="${labelStyle}">Godzina</div><div style="${valueStyle}">${timeStr}</div></div>
  </div>`;

if (data.location) {
  rows += `
  <div style="${rowStyle}">
    <span style="font-size:22px;width:28px;text-align:center;">📍</span>
    <div><div style="${labelStyle}">Miejsce</div><div style="${valueStyle}">${data.location}</div></div>
  </div>`;
}
if (data.notes) {
  rows += `
  <div style="${rowStyle.replace('border-bottom:1px solid #eef1f5;','')}">
    <span style="font-size:22px;width:28px;text-align:center;">💬</span>
    <div><div style="${labelStyle}">Notatka</div><div style="font-size:14px;color:#444;">${data.notes}</div></div>
  </div>`;
}

const html = `<!DOCTYPE html>
<html lang="pl">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:24px 16px;background:#f0f4f8;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;">
  <div style="max-width:460px;margin:0 auto;">
    <div style="background:#0f1f3d;border-radius:16px 16px 0 0;padding:28px 24px;text-align:center;">
      <div style="font-size:44px;margin-bottom:8px;">${emoji}</div>
      <div style="display:inline-block;background:rgba(0,201,167,0.15);color:#00c9a7;font-size:10px;font-weight:700;letter-spacing:2px;text-transform:uppercase;padding:4px 12px;border-radius:20px;margin-bottom:10px;">${catName}</div>
      <div style="color:#ffffff;font-size:21px;font-weight:700;line-height:1.3;">${title}</div>
    </div>
    <div style="background:#ffffff;padding:20px 24px;border-radius:0 0 16px 16px;box-shadow:0 4px 20px rgba(0,0,0,0.08);">
      ${rows}
      <div style="margin-top:20px;padding:14px;background:#f8fafc;border-radius:10px;text-align:center;">
        <a href="http://localhost:8080/index.html#${data.familyId || ''}" style="color:#00c9a7;font-size:13px;font-weight:600;text-decoration:none;">📱 Otwórz Rodzinny Kalendarz</a>
      </div>
    </div>
    <div style="text-align:center;padding:16px;">
      <div style="font-size:11px;color:#9aa5b4;">Rodzinny Kalendarz · powiadomienie automatyczne</div>
    </div>
  </div>
</body>
</html>`;

const subject = `${emoji} ${catName}: ${title} · ${shortDate}`;

return [{ json: { html, subject, toTata: TATA_EMAIL, toMama: MAMA_EMAIL } }];

// Oblicz czas przypomnienia = wydarzenie - 3 godziny
const raw = $input.first().json.body || $input.first().json;

// Potrzebujemy daty i godziny
if (!raw.date || !raw.time) return []; // brak godziny = brak przypomnienia

const [year, month, day] = raw.date.split('-').map(Number);
const [hour, minute]     = raw.time.split(':').map(Number);

// Czas wydarzenia (strefa Warsaw)
const eventMs    = new Date(year, month - 1, day, hour, minute, 0).getTime();
const reminderMs = eventMs - 3 * 60 * 60 * 1000; // -3h
const nowMs      = Date.now();

// Jeśli przypomnienie byłoby w przeszłości — pomijamy
if (reminderMs <= nowMs) return [];

const resumeAt = new Date(reminderMs).toISOString();

return [{ json: { ...raw, resumeAt } }];

